// Board items — CRUD against the polymorphic Item table for the
// canonical studio-item flavor. The Item model's `(itemType, itemId)`
// pair points to whichever entity backs the row; for studio-item
// boards `itemType = "studio-item"` and we mint our own `itemId`
// (cuid generated by Prisma — we use a synthetic cuid here so the
// unique constraint holds).
//
// Row data layout:
//   item.title    — the hoisted Title cell (always present)
//   item.status   — the hoisted Status cell (single-select string)
//   item.ownerId  — assignee user id (nullable)
//   item.metadata — JSON map for any other column values (Phase 3c
//                   field shelf writes here)
//
// Default status palette (used when Board.schema.fields doesn't yet
// define one — Phase 3c will override per-board):
//   TO_DO        slate
//   IN_PROGRESS  blue
//   DONE         green

import { prisma } from "@/lib/prisma";
import { logActivity } from "@/lib/item-thread";
import { parseRecurrence } from "@/lib/recurrence";
import {
  DEFAULT_STATUS_OPTIONS,
  PRIORITY_OPTIONS,
  getBoardStatuses,
  isDoneStatus,
  makeStatusLookup,
  parseBoardStatuses,
  type BoardItemRow,
  type ItemTag,
  type StatusGroup,
  type StatusOption,
} from "@/lib/board-items-shared";

// Re-export the client-safe pieces so existing server code (API routes,
// page server components) keeps working with `from "@/lib/board-items"`.
// Client components must import from `@/lib/board-items-shared` directly
// to avoid pulling Prisma + pg into the browser bundle.
export {
  DEFAULT_STATUS_OPTIONS,
  PRIORITY_OPTIONS,
  getBoardStatuses,
  isDoneStatus,
  makeStatusLookup,
  parseBoardStatuses,
  type BoardItemRow,
  type ItemTag,
  type StatusGroup,
  type StatusOption,
};

function rowFrom(it: {
  id: string;
  title: string;
  status: string | null;
  ownerId: string | null;
  groupKey: string | null;
  position: number;
  metadata: unknown;
  startAt?: Date | null;
  dueAt?: Date | null;
  priority?: string | null;
  itemTypeId?: string | null;
  parentItemId?: string | null;
  recurRule?: unknown;
  recurNextAt?: Date | null;
  archivedAt: Date | null;
  createdAt: Date;
  updatedAt: Date;
}, owner?: { id: string; firstName: string; lastName: string; avatar: string | null } | null, tags?: ItemTag[]): BoardItemRow {
  return {
    id: it.id,
    title: it.title,
    status: it.status,
    ownerId: it.ownerId,
    groupKey: it.groupKey,
    position: it.position,
    metadata: (it.metadata as Record<string, unknown>) ?? {},
    startAt: it.startAt ?? null,
    dueAt: it.dueAt ?? null,
    priority: it.priority ?? null,
    itemTypeId: it.itemTypeId ?? null,
    parentItemId: it.parentItemId ?? null,
    recurRule: parseRecurrence(it.recurRule),
    recurNextAt: it.recurNextAt ?? null,
    archivedAt: it.archivedAt,
    createdAt: it.createdAt,
    updatedAt: it.updatedAt,
    owner: owner ?? null,
    tags: tags ?? [],
  };
}

const VALID_PRIORITIES = new Set<string>(PRIORITY_OPTIONS.map((p) => p.value));

function normalizePriority(value: string | null | undefined): string | null {
  if (value == null) return null;
  const up = value.toUpperCase();
  if (!VALID_PRIORITIES.has(up)) throw new Error(`Invalid priority: ${value}`);
  return up;
}

/** Batched tag fetch for a set of items → Map(itemId → ItemTag[]). */
async function tagsForItems(itemIds: string[]): Promise<Map<string, ItemTag[]>> {
  const map = new Map<string, ItemTag[]>();
  if (!itemIds.length) return map;
  const assignments = await prisma.tagAssignment.findMany({
    where: { entityType: "BOARD_ITEM", entityId: { in: itemIds } },
    include: { tag: { select: { id: true, name: true, color: true, archived: true } } },
    orderBy: { createdAt: "asc" },
  });
  for (const a of assignments) {
    if (a.tag.archived) continue;
    const list = map.get(a.entityId) ?? [];
    list.push({ id: a.tag.id, name: a.tag.name, color: a.tag.color });
    map.set(a.entityId, list);
  }
  return map;
}

/** Diff-sync an item's BOARD_ITEM TagAssignments to exactly `tagIds`. */
async function syncItemTags(
  organizationId: string,
  itemId: string,
  tagIds: string[],
  actorId: string | null,
): Promise<ItemTag[]> {
  // Only org-owned, non-archived tags are assignable.
  const valid = tagIds.length
    ? await prisma.tag.findMany({
        where: { organizationId, id: { in: tagIds }, archived: false },
        select: { id: true, name: true, color: true },
      })
    : [];
  const validIds = new Set(valid.map((t) => t.id));

  const existing = await prisma.tagAssignment.findMany({
    where: { entityType: "BOARD_ITEM", entityId: itemId },
    select: { id: true, tagId: true },
  });
  const existingByTag = new Map(existing.map((e) => [e.tagId, e.id] as const));

  const toAdd = [...validIds].filter((id) => !existingByTag.has(id));
  const toRemove = existing.filter((e) => !validIds.has(e.tagId));

  await Promise.all([
    toAdd.length
      ? prisma.tagAssignment.createMany({
          data: toAdd.map((tagId) => ({
            tagId,
            entityType: "BOARD_ITEM" as const,
            entityId: itemId,
            organizationId,
            assignedById: actorId,
          })),
          skipDuplicates: true,
        })
      : Promise.resolve(null),
    toRemove.length
      ? prisma.tagAssignment.deleteMany({ where: { id: { in: toRemove.map((e) => e.id) } } })
      : Promise.resolve(null),
  ]);

  // Keep the caller's requested order where possible.
  const byId = new Map(valid.map((t) => [t.id, t] as const));
  return tagIds.filter((id) => byId.has(id)).map((id) => byId.get(id)!);
}

export async function listBoardItems(boardId: string, opts: { includeArchived?: boolean } = {}): Promise<BoardItemRow[]> {
  const rows = await prisma.item.findMany({
    where: {
      boardId,
      ...(opts.includeArchived ? {} : { archivedAt: null }),
    },
    orderBy: { position: "asc" },
  });

  const itemIds = rows.map((r) => r.id);
  const ownerIds = Array.from(new Set(rows.map((r) => r.ownerId).filter((x): x is string => !!x)));

  // Parallel batches — owners + comment counts + links (by type) + tags +
  // time-tracked sum + creator activity. All polymorphic aggregates key off
  // (entityType/entityId or sourceType/sourceId) via groupBy, so no N+1.
  const [owners, commentGroups, linkGroups, tagsById, timeGroups, createdActs] = await Promise.all([
    ownerIds.length
      ? prisma.user.findMany({
          where: { id: { in: ownerIds } },
          select: { id: true, firstName: true, lastName: true, avatar: true },
        })
      : Promise.resolve([] as { id: string; firstName: string; lastName: string; avatar: string | null }[]),
    itemIds.length
      ? prisma.itemUpdate.groupBy({
          by: ["entityId"],
          where: { entityType: "BOARD_ITEM", entityId: { in: itemIds } },
          _count: { _all: true },
        })
      : Promise.resolve([] as { entityId: string; _count: { _all: number } }[]),
    itemIds.length
      ? prisma.entityLink.groupBy({
          by: ["sourceId", "targetType"],
          where: { sourceType: "BOARD_ITEM", sourceId: { in: itemIds } },
          _count: { _all: true },
        })
      : Promise.resolve([] as { sourceId: string; targetType: string; _count: { _all: number } }[]),
    tagsForItems(itemIds),
    itemIds.length
      ? prisma.timerSession.groupBy({
          by: ["entityId"],
          where: { entityType: "BOARD_ITEM", entityId: { in: itemIds } },
          _sum: { durationMs: true },
        })
      : Promise.resolve([] as { entityId: string; _sum: { durationMs: number | null } }[]),
    itemIds.length
      ? prisma.itemActivity.findMany({
          where: { entityType: "BOARD_ITEM", entityId: { in: itemIds }, action: "CREATED" },
          select: { entityId: true, actorId: true },
        })
      : Promise.resolve([] as { entityId: string; actorId: string | null }[]),
  ]);

  const ownerById = new Map(owners.map((o) => [o.id, o] as const));
  const commentCountById = new Map(commentGroups.map((g) => [g.entityId, g._count._all] as const));

  // Links split by target type — total (attachmentCount) + typed counts.
  const attachmentCountById = new Map<string, number>();
  const linkedDocById = new Map<string, number>();
  const linkedTaskById = new Map<string, number>();
  const linkedSopById = new Map<string, number>();
  for (const g of linkGroups) {
    const n = g._count._all;
    attachmentCountById.set(g.sourceId, (attachmentCountById.get(g.sourceId) ?? 0) + n);
    if (g.targetType === "DOC") linkedDocById.set(g.sourceId, n);
    else if (g.targetType === "BOARD_ITEM") linkedTaskById.set(g.sourceId, n);
    else if (g.targetType === "SOP") linkedSopById.set(g.sourceId, n);
  }
  const timeById = new Map(timeGroups.map((g) => [g.entityId, g._sum.durationMs ?? 0] as const));

  // Creator = the actor on the item's CREATED activity. Resolve any creators
  // not already in the owner batch with one extra lookup.
  const creatorIdByItem = new Map<string, string>();
  for (const a of createdActs) {
    if (a.actorId && !creatorIdByItem.has(a.entityId)) creatorIdByItem.set(a.entityId, a.actorId);
  }
  const creatorUserById = new Map(ownerById);
  const extraCreatorIds = Array.from(new Set([...creatorIdByItem.values()])).filter((id) => !creatorUserById.has(id));
  if (extraCreatorIds.length) {
    const extra = await prisma.user.findMany({
      where: { id: { in: extraCreatorIds } },
      select: { id: true, firstName: true, lastName: true, avatar: true },
    });
    for (const u of extra) creatorUserById.set(u.id, u);
  }

  // Subtask counts derived from the same fetched rows — no extra query.
  // Top-level item (parentItemId = null) gets count of its direct children.
  const subtaskCountByParent = new Map<string, number>();
  for (const r of rows) {
    if (r.parentItemId) {
      subtaskCountByParent.set(r.parentItemId, (subtaskCountByParent.get(r.parentItemId) ?? 0) + 1);
    }
  }

  return rows.map((r) => {
    const base = rowFrom(r, r.ownerId ? ownerById.get(r.ownerId) ?? null : null, tagsById.get(r.id) ?? []);
    base.commentCount = commentCountById.get(r.id) ?? 0;
    base.attachmentCount = attachmentCountById.get(r.id) ?? 0;
    base.subtaskCount = subtaskCountByParent.get(r.id) ?? 0;
    base.timeTrackedMs = timeById.get(r.id) ?? 0;
    base.linkedDocCount = linkedDocById.get(r.id) ?? 0;
    base.linkedTaskCount = linkedTaskById.get(r.id) ?? 0;
    base.linkedSopCount = linkedSopById.get(r.id) ?? 0;
    const cid = creatorIdByItem.get(r.id);
    base.createdBy = cid ? creatorUserById.get(cid) ?? null : null;
    return base;
  });
}

export interface CreateBoardItemInput {
  organizationId: string;
  boardId: string;
  title: string;
  status?: string;
  ownerId?: string;
  groupKey?: string;
  metadata?: Record<string, unknown>;
  /** Phase 58 dates — ISO strings or Date; coerced before Prisma. */
  startAt?: string | Date | null;
  dueAt?: string | Date | null;
  /** Task-system phase 2 — URGENT|HIGH|NORMAL|LOW (case-insensitive). */
  priority?: string | null;
  /** Task Types — the ItemType to re-skin this row as. null = default. */
  itemTypeId?: string | null;
  /** Task-system phase 2 — workspace Tag ids to assign at create. */
  tagIds?: string[];
  /** Phase 72 — null = top-level item; set to a parent id to create a subtask. */
  parentItemId?: string | null;
  /** Logged on the activity feed for this item. Pass the session
   *  user's id; null only for system-generated rows. */
  actorId?: string | null;
}

/**
 * Append a new item to the end of a board. Position = max + 1024 to
 * preserve room for fractional inserts later. Generates a synthetic
 * itemId so the unique (itemType, itemId) constraint holds.
 */
export async function createBoardItem(input: CreateBoardItemInput): Promise<BoardItemRow> {
  const trimmed = input.title.trim();
  if (!trimmed) throw new Error("Title is required");

  // Position scoped to the parent: subtasks order among themselves,
  // top-level items order among themselves. Otherwise creating the
  // first subtask under any parent would land at the bottom of the
  // whole board's position space.
  const last = await prisma.item.findFirst({
    where: { boardId: input.boardId, parentItemId: input.parentItemId ?? null },
    orderBy: { position: "desc" },
    select: { position: true },
  });
  const position = (last?.position ?? 0) + 1024;

  // Synthetic itemId — for studio-item rows the Item row IS the row;
  // there's no separate canonical entity table. We use the row's own
  // id so itemId == id; the unique constraint becomes per-row.
  const id = cuid();
  const created = await prisma.item.create({
    data: {
      id,
      organizationId: input.organizationId,
      boardId: input.boardId,
      itemType: "studio-item",
      itemId: id,
      title: trimmed,
      status: input.status ?? "TO_DO",
      ownerId: input.ownerId ?? null,
      groupKey: input.groupKey ?? null,
      position,
      startAt: input.startAt == null ? null : new Date(input.startAt),
      dueAt: input.dueAt == null ? null : new Date(input.dueAt),
      priority: normalizePriority(input.priority),
      itemTypeId: input.itemTypeId ?? null,
      metadata: (input.metadata ?? {}) as object,
      parentItemId: input.parentItemId ?? null,
    },
  });
  const tags = input.tagIds?.length
    ? await syncItemTags(input.organizationId, created.id, input.tagIds, input.actorId ?? null)
    : [];
  const owner = input.ownerId
    ? await prisma.user.findUnique({
        where: { id: input.ownerId },
        select: { id: true, firstName: true, lastName: true, avatar: true },
      })
    : null;

  await logActivity({
    organizationId: input.organizationId,
    itemId: created.id,
    actorId: input.actorId ?? null,
    action: "CREATED",
    meta: { title: trimmed, status: created.status },
  });

  return rowFrom(created, owner, tags);
}

export interface UpdateBoardItemInput {
  title?: string;
  status?: string | null;
  ownerId?: string | null;
  groupKey?: string | null;
  position?: number;
  metadata?: Record<string, unknown>;
  // Phase 58 — ISO strings accepted from the API layer; coerced to Date
  // before reaching Prisma so the schema's DateTime type is happy.
  startAt?: string | Date | null;
  dueAt?: string | Date | null;
  /** Task-system phase 2 — URGENT|HIGH|NORMAL|LOW or null to clear. */
  priority?: string | null;
  /** Task Types — re-skin this row as an ItemType (null = default). */
  itemTypeId?: string | null;
  /** Task-system phase 2 — full replacement set of workspace Tag ids. */
  tagIds?: string[];
  /** Recurring tasks — the series rule ({freq,interval}) or null to stop
   *  repeating. recurNextAt is computed server-side, never set by callers. */
  recurRule?: Record<string, unknown> | null;
  /** Internal: the cron + PATCH route set the next spawn time directly. */
  recurNextAt?: Date | null;
}

export async function updateBoardItem(
  itemId: string,
  patch: UpdateBoardItemInput,
  actorId: string | null = null,
): Promise<BoardItemRow> {
  // Capture the pre-edit values so we can diff for the activity log.
  const before = await prisma.item.findUnique({
    where: { id: itemId },
    select: { organizationId: true, title: true, status: true, ownerId: true, priority: true },
  });

  const data: Record<string, unknown> = {};
  if (patch.title !== undefined) {
    const trimmed = patch.title.trim();
    if (!trimmed) throw new Error("Title cannot be empty");
    data.title = trimmed;
  }
  if (patch.status !== undefined) data.status = patch.status;
  if (patch.ownerId !== undefined) data.ownerId = patch.ownerId;
  if (patch.groupKey !== undefined) data.groupKey = patch.groupKey;
  if (patch.position !== undefined) data.position = patch.position;
  if (patch.metadata !== undefined) data.metadata = patch.metadata as object;
  if (patch.startAt !== undefined) data.startAt = patch.startAt === null ? null : new Date(patch.startAt);
  if (patch.dueAt !== undefined) data.dueAt = patch.dueAt === null ? null : new Date(patch.dueAt);
  if (patch.priority !== undefined) data.priority = normalizePriority(patch.priority);
  if (patch.itemTypeId !== undefined) data.itemTypeId = patch.itemTypeId;
  if (patch.recurRule !== undefined) data.recurRule = patch.recurRule ?? null;
  if (patch.recurNextAt !== undefined) data.recurNextAt = patch.recurNextAt;

  const updated = await prisma.item.update({ where: { id: itemId }, data });
  const owner = updated.ownerId
    ? await prisma.user.findUnique({
        where: { id: updated.ownerId },
        select: { id: true, firstName: true, lastName: true, avatar: true },
      })
    : null;

  const tags = patch.tagIds !== undefined
    ? await syncItemTags(updated.organizationId, itemId, patch.tagIds, actorId)
    : (await tagsForItems([itemId])).get(itemId) ?? [];

  if (before) {
    if (patch.title !== undefined && before.title !== updated.title) {
      await logActivity({
        organizationId: before.organizationId,
        itemId,
        actorId,
        action: "TITLE_CHANGED",
        meta: { from: before.title, to: updated.title },
      });
    }
    if (patch.status !== undefined && before.status !== updated.status) {
      await logActivity({
        organizationId: before.organizationId,
        itemId,
        actorId,
        action: "STATUS_CHANGED",
        meta: { from: before.status, to: updated.status },
      });
    }
    if (patch.ownerId !== undefined && before.ownerId !== updated.ownerId) {
      await logActivity({
        organizationId: before.organizationId,
        itemId,
        actorId,
        action: "OWNER_CHANGED",
        meta: { from: before.ownerId, to: updated.ownerId },
      });
    }
    if (patch.priority !== undefined && before.priority !== updated.priority) {
      await logActivity({
        organizationId: before.organizationId,
        itemId,
        actorId,
        action: "PRIORITY_CHANGED",
        meta: { from: before.priority, to: updated.priority },
      });
    }
    if (patch.metadata !== undefined) {
      await logActivity({
        organizationId: before.organizationId,
        itemId,
        actorId,
        action: "FIELDS_UPDATED",
        meta: {},
      });
    }
  }

  return rowFrom(updated, owner, tags);
}

export async function archiveBoardItem(itemId: string, actorId: string | null = null): Promise<BoardItemRow> {
  const updated = await prisma.item.update({
    where: { id: itemId },
    data: { archivedAt: new Date() },
  });
  await logActivity({
    organizationId: updated.organizationId,
    itemId,
    actorId,
    action: "ARCHIVED",
    meta: {},
  });
  return rowFrom(updated);
}

export async function deleteBoardItem(itemId: string): Promise<void> {
  await prisma.item.delete({ where: { id: itemId } });
}

// ── Internal: cuid (Prisma's cuid v1 algorithm without the dep) ──
//
// We generate the row's own primary key client-side here because we
// also write it into the polymorphic `itemId` column to satisfy the
// (itemType, itemId) unique constraint. Prisma's @default(cuid()) only
// fires on auto-generated PKs, so we mirror its behavior in TS.
function cuid(): string {
  const ts = Date.now().toString(36);
  const r = Array.from({ length: 16 }, () =>
    Math.floor(Math.random() * 36).toString(36),
  ).join("");
  return `c${ts}${r}`.slice(0, 25);
}
